62	const defaultBaseURL = 'https://api.bfl.ai/v1';
63	
64	export function createBlackForestLabs(
65	  options: BlackForestLabsProviderSettings = {},
66	): BlackForestLabsProvider {
67	  const baseURL = withoutTrailingSlash(options.baseURL ?? defaultBaseURL);
68	  const getHeaders = () =>
69	    withUserAgentSuffix(
70	      {
71	        'x-key': loadApiKey({
72	          apiKey: options.apiKey,
73	          environmentVariableName: 'BFL_API_KEY',
74	          description: 'Black Forest Labs',
75	        }),
76	        ...options.headers,
77	      },
78	      `ai-sdk/black-forest-labs/${VERSION}`,
79	    );
80	
81	  const createImageModel = (modelId: BlackForestLabsImageModelId) =>
82	    new BlackForestLabsImageModel(modelId, {
83	      provider: 'black-forest-labs.image',
84	      baseURL: baseURL ?? defaultBaseURL,
85	      headers: getHeaders,
86	      fetch: options.fetch,
87	      pollIntervalMillis: options.pollIntervalMillis,
88	      pollTimeoutMillis: options.pollTimeoutMillis,
89	    });
90	
91	  const embeddingModel = (modelId: string) => {
92	    throw new NoSuchModelError({
93	      modelId,
94	      modelType: 'embeddingModel',
95	    });
96	  };
97	
98	  return {
99	    specificationVersion: 'v3',
100	    imageModel: createImageModel,
101	    image: createImageModel,
102	    languageModel: (modelId: string) => {
103	      throw new NoSuchModelError({
104	        modelId,
105	        modelType: 'languageModel',
106	      });
107	    },
108	    embeddingModel,
109	    textEmbeddingModel: embeddingModel,
110	  };
111	}
