import type { ImageModelV3, SharedV3Warning } from '@ai-sdk/provider';
import type { InferSchema, Resolvable } from '@ai-sdk/provider-utils';
import {
  FetchFunction,
  combineHeaders,
  createBinaryResponseHandler,
  createJsonErrorResponseHandler,
  createJsonResponseHandler,
  lazySchema,
  parseProviderOptions,
  postJsonToApi,
  resolve,
  zodSchema,
} from '@ai-sdk/provider-utils';
import { z } from 'zod/v4';
import type { PixelArtImageModelId } from './pixelart-image-settings';

interface PixelArtImageModelConfig {
  provider: string;
  baseURL: string;
  headers?: Resolvable<Record<string, string | undefined>>;
  fetch?: FetchFunction;
  _internal?: {
    currentDate?: () => Date;
  };
}

export class PixelArtImageModel implements ImageModelV3 {
  readonly specificationVersion = 'v3';
  readonly maxImagesPerCall = 1;

  get provider(): string {
    return this.config.provider;
  }

  constructor(
    readonly modelId: PixelArtImageModelId,
    private readonly config: PixelArtImageModelConfig,
  ) {}

  private async getArgs({
    prompt,
    n,
    size,
    aspectRatio,
    seed,
    providerOptions,
  }: Parameters<ImageModelV3['doGenerate']>[0]) {
    const warnings: Array<SharedV3Warning> = [];

    // n > 1 is unsupported — the API generates one image per call
    if (n != null && n > 1) {
      warnings.push({
        type: 'unsupported',
        feature: 'n',
        details:
          'PixelArt only supports generating one image per call. n > 1 is ignored.',
      });
    }

    // aspectRatio is unsupported — use size instead
    if (aspectRatio != null) {
      warnings.push({
        type: 'unsupported',
        feature: 'aspectRatio',
        details:
          'PixelArt does not support aspectRatio. Use the size parameter to specify dimensions.',
      });
    }

    const pixelArtOptions = await parseProviderOptions({
      provider: 'pixelArt',
      providerOptions,
      schema: pixelArtImageModelOptionsSchema,
    });

    // Parse width/height from size string (e.g. "512x512")
    let width: number | undefined;
    let height: number | undefined;
    if (size != null) {
      const [wStr, hStr] = size.split('x');
      const parsedWidth = Number(wStr);
      const parsedHeight = Number(hStr);
      if (
        Number.isFinite(parsedWidth) &&
        parsedWidth > 0 &&
        Number.isFinite(parsedHeight) &&
        parsedHeight > 0
      ) {
        width = parsedWidth;
        height = parsedHeight;
      } else {
        warnings.push({
          type: 'other',
          message: `PixelArt received an unrecognized size value "${size}" — it will be ignored.`,
        });
      }
    }

    const body: Record<string, unknown> = {
      prompt,
      model: this.modelId,
      ...(width != null && { width }),
      ...(height != null && { height }),
      ...(seed != null && { seed }),
      ...(pixelArtOptions?.style != null && { style: pixelArtOptions.style }),
      ...(pixelArtOptions?.pixelDensity != null && {
        pixel_density: pixelArtOptions.pixelDensity,
      }),
      ...(pixelArtOptions?.outputFormat != null && {
        output_format: pixelArtOptions.outputFormat,
      }),
    };

    return { body, warnings };
  }

  async doGenerate({
    prompt,
    n,
    size,
    aspectRatio,
    seed,
    providerOptions,
    headers,
    abortSignal,
    files,
    mask,
  }: Parameters<ImageModelV3['doGenerate']>[0]): Promise<
    Awaited<ReturnType<ImageModelV3['doGenerate']>>
  > {
    const { body, warnings } = await this.getArgs({
      prompt,
      n,
      size,
      aspectRatio,
      seed,
      providerOptions,
      headers,
      abortSignal,
      files,
      mask,
    });

    const currentDate = this.config._internal?.currentDate?.() ?? new Date();
    const combinedHeaders = combineHeaders(
      await resolve(this.config.headers),
      headers,
    );

    const { value: imageBytes, responseHeaders } = await postJsonToApi({
      url: `${this.config.baseURL}/generate`,
      headers: combinedHeaders,
      body,
      failedResponseHandler: pixelArtFailedResponseHandler,
      successfulResponseHandler: createBinaryResponseHandler(),
      abortSignal,
      fetch: this.config.fetch,
    });

    return {
      images: [imageBytes],
      warnings,
      response: {
        modelId: this.modelId,
        timestamp: currentDate,
        headers: responseHeaders,
      },
    };
  }
}

export const pixelArtImageModelOptionsSchema = lazySchema(() =>
  zodSchema(
    z.object({
      /**
       * Visual style of the generated image.
       * - `pixel`  – Classic pixel-art style with a limited palette.
       * - `retro`  – Retro aesthetic inspired by early home computers.
       * - `8bit`   – Hard-edged 8-bit game graphics look.
       */
      style: z.enum(['pixel', 'retro', '8bit']).optional(),

      /**
       * Pixel density (dots per pixel block). Higher values produce finer
       * detail within each pixel cell. Accepted range: 1–16.
       */
      pixelDensity: z.number().int().min(1).max(16).optional(),

      /**
       * Output image format returned by the API.
       */
      outputFormat: z.enum(['png', 'jpeg', 'webp']).optional(),
    }),
  ),
);

export type PixelArtImageModelOptions = InferSchema<
  typeof pixelArtImageModelOptionsSchema
>;

// ---------------------------------------------------------------------------
// Response schemas
// ---------------------------------------------------------------------------

const pixelArtErrorSchema = z.object({
  error: z.string().optional(),
  message: z.string().optional(),
});

const pixelArtFailedResponseHandler = createJsonErrorResponseHandler({
  errorSchema: pixelArtErrorSchema,
  errorToMessage: error => {
    const parsed = pixelArtErrorSchema.safeParse(error);
    if (!parsed.success) return 'Unknown PixelArt error';
    const { error: errorMsg, message } = parsed.data;
    return errorMsg ?? message ?? 'Unknown PixelArt error';
  },
});

// Exported for use in tests
export { pixelArtFailedResponseHandler };

// ---------------------------------------------------------------------------
// Utility — kept here for completeness; unused internally but useful for
// consumers who want to build response-schema validators.
// ---------------------------------------------------------------------------
export const pixelArtGenerateResponseSchema = z.object({
  id: z.string().optional(),
  created: z.number().optional(),
  model: z.string().optional(),
  usage: z
    .object({
      prompt_tokens: z.number().optional(),
      total_tokens: z.number().optional(),
    })
    .optional(),
});

