import { NoSuchModelError } from '@ai-sdk/provider';
import { describe, expect, it } from 'vitest';
import { PixelArtImageModel } from './pixelart-image-model';
import { createPixelArt, pixelart } from './pixelart-provider';

describe('createPixelArt', () => {
  describe('image / imageModel', () => {
    it('returns a PixelArtImageModel instance', () => {
      const provider = createPixelArt({ apiKey: 'test-key' });
      const model = provider.image('pixelart-standard');

      expect(model).toBeInstanceOf(PixelArtImageModel);
    });

    it('image and imageModel return equivalent instances', () => {
      const provider = createPixelArt({ apiKey: 'test-key' });
      const via_image = provider.image('pixelart-pro');
      const via_imageModel = provider.imageModel('pixelart-pro');

      expect(via_image.modelId).toBe(via_imageModel.modelId);
      expect(via_image.provider).toBe(via_imageModel.provider);
    });

    it('sets the correct modelId', () => {
      const provider = createPixelArt({ apiKey: 'test-key' });
      const model = provider.image('pixelart-ultra');

      expect(model.modelId).toBe('pixelart-ultra');
    });

    it('sets the correct provider string', () => {
      const provider = createPixelArt({ apiKey: 'test-key' });
      const model = provider.image('pixelart-standard');

      expect(model.provider).toBe('pixelart.image');
    });

    it('respects a custom baseURL', () => {
      const provider = createPixelArt({
        apiKey: 'test-key',
        baseURL: 'https://custom.example.com/api',
      });
      const model = provider.image('pixelart-standard') as PixelArtImageModel;

      // The baseURL is stored in the private config; we just verify no error
      expect(model).toBeInstanceOf(PixelArtImageModel);
    });

    it('strips trailing slash from custom baseURL', () => {
      // Should not throw — withoutTrailingSlash handles normalisation
      const provider = createPixelArt({
        apiKey: 'test-key',
        baseURL: 'https://custom.example.com/api/',
      });
      expect(provider.image('pixelart-standard')).toBeInstanceOf(
        PixelArtImageModel,
      );
    });
  });

  describe('unsupported model types', () => {
    it('throws NoSuchModelError for languageModel', () => {
      const provider = createPixelArt({ apiKey: 'test-key' });

      expect(() => provider.languageModel('gpt-4')).toThrow(NoSuchModelError);
    });

    it('throws NoSuchModelError for embeddingModel', () => {
      const provider = createPixelArt({ apiKey: 'test-key' });

      expect(() => provider.embeddingModel('text-embedding-3-small')).toThrow(
        NoSuchModelError,
      );
    });

    it('throws NoSuchModelError for textEmbeddingModel', () => {
      const provider = createPixelArt({ apiKey: 'test-key' });

      expect(() =>
        (provider as any).textEmbeddingModel('text-embedding-3-small'),
      ).toThrow(NoSuchModelError);
    });
  });

  describe('specificationVersion', () => {
    it('is v3', () => {
      const provider = createPixelArt({ apiKey: 'test-key' });
      expect(provider.specificationVersion).toBe('v3');
    });
  });
});

describe('pixelart (default instance)', () => {
  it('is a PixelArtProvider', () => {
    expect(pixelart).toBeDefined();
    expect(pixelart.specificationVersion).toBe('v3');
  });

  it('creates image models', () => {
    // Don't actually make network calls — just verify factory works
    const model = pixelart.image('pixelart-standard');
    expect(model).toBeInstanceOf(PixelArtImageModel);
    expect(model.modelId).toBe('pixelart-standard');
  });
});

